pub fn is_valid_ipv4(s: &str) -> bool {
    let parts: Vec<&str> = s.split('.').collect();
    if parts.len() != 4 { return false; }
    parts.iter().all(|p| {
        if p.is_empty() || (p.len() > 1 && p.starts_with('0')) { return false; }
        p.parse::<u8>().is_ok()
    })
}

